1	type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const cellKey = (x: number, y: number): string => `${x},${y}`;
10	const parseKey = (key: string): Cell => key.split(",").map(Number) as Cell;
11	
12	const survivesOrIsBorn = (isAlive: boolean, neighborCount: number): boolean =>
13	  neighborCount === 3 || (isAlive && neighborCount === 2);
14	
15	const countNeighbors = (cells: Cell[]): Map<string, number> => {
16	  const counts = new Map<string, number>();
17	  for (const [x, y] of cells) {
18	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
19	      const key = cellKey(x + dx, y + dy);
20	      counts.set(key, (counts.get(key) ?? 0) + 1);
21	    }
22	  }
23	  return counts;
24	};
25	
26	export function nextGeneration(cells: Cell[]): Cell[] {
27	  const liveSet = new Set(cells.map(([x, y]) => cellKey(x, y)));
28	  const neighborCounts = countNeighbors(cells);
29	
30	  const result: Cell[] = [];
31	  for (const [key, count] of neighborCounts) {
32	    if (survivesOrIsBorn(liveSet.has(key), count)) {
33	      result.push(parseKey(key));
34	    }
35	  }
36	
37	  return result;
38	}
39

1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Conway's Game of Life - Next Generation", () => {
5	  it("should return empty array for empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should return empty array for a single live cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should return empty array for two adjacent live cells (underpopulation)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should create a new live cell at a dead position with exactly 3 live neighbors (reproduction)", () => {
15	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
16	    expect(result).toContainEqual([1, 1]);
17	  });
18	  it("should keep a live cell alive when it has 2 or 3 live neighbors (survival)", () => {
19	    const result = nextGeneration([[0, 0], [0, 1], [0, 2]]);
20	    expect(result).toContainEqual([0, 1]);
21	  });
22	  it("should kill a live cell with more than 3 live neighbors (overpopulation)", () => {
23	    const result = nextGeneration([
24	      [0, 0], [1, 0], [2, 0],
25	      [0, 1], [1, 1], [2, 1],
26	      [0, 2], [1, 2], [2, 2],
27	    ]);
28	    expect(result).not.toContainEqual([1, 1]);
29	  });
30	  it("should keep a block still life unchanged: [(0,0),(1,0),(0,1),(1,1)] stays the same", () => {
31	    const input: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
32	    const result = nextGeneration(input);
33	    const toKey = (c: [number, number]) => `${c[0]},${c[1]}`;
34	    expect(new Set(result.map(toKey))).toEqual(new Set(input.map(toKey)));
35	  });
36	  it("should oscillate a blinker: [(0,0),(0,1),(0,2)] becomes [(-1,1),(0,1),(1,1)]", () => {
37	    const input: [number, number][] = [[0, 0], [0, 1], [0, 2]];
38	    const result = nextGeneration(input);
39	    const sortKey = (c: [number, number]) => `${c[0]},${c[1]}`;
40	    const expected: [number, number][] = [[-1, 1], [0, 1], [1, 1]];
41	    expect(result.map(sortKey).sort()).toEqual(expected.map(sortKey).sort());
42	  });
43	});
